기존에 아래와 같은 쿼리들이 있어. 이 쿼리들은 살려놔야 할까? 삭제해야 할까?
1.
-- 1. 학생 삭제 함수 (연관된 모든 데이터 정리 후 삭제)
CREATE OR REPLACE FUNCTION delete_student(p_user_id text)
RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
  v_account_id text;
BEGIN
  -- 학생의 계좌 ID 조회
  SELECT "accountId" INTO v_account_id FROM accounts WHERE "userId" = p_user_id;

  -- 1. 직업 배정 내역 삭제
  DELETE FROM job_assignments WHERE "studentUserId" = p_user_id;

  -- 2. 보유 주식 삭제
  DELETE FROM student_stocks WHERE "userId" = p_user_id;

  -- 3. 가입 적금 삭제
  DELETE FROM student_savings WHERE "userId" = p_user_id;

  -- 4. 거래 내역 처리
  -- 4-1. 내 계좌의 거래 내역은 모두 삭제
  IF v_account_id IS NOT NULL THEN
    DELETE FROM transactions WHERE "accountId" = v_account_id;
  END IF;

  -- 4-2. 내가 다른 사람과 거래했던 기록(송금 보냄/받음)에서 내 ID를 지움 (참조 무결성 오류 방지)
  UPDATE transactions SET "senderId" = NULL WHERE "senderId" = p_user_id;
  UPDATE transactions SET "receiverId" = NULL WHERE "receiverId" = p_user_id;

  -- 5. 계좌 삭제
  DELETE FROM accounts WHERE "userId" = p_user_id;

  -- 6. 사용자(학생) 삭제
  DELETE FROM users WHERE "userId" = p_user_id;
END;
$$;

-- 2. 직업 삭제 함수 (배정된 내역 먼저 삭제)
CREATE OR REPLACE FUNCTION delete_job(p_job_id uuid)
RETURNS void
LANGUAGE plpgsql
AS $$
BEGIN
  -- 1. 이 직업에 배정된 학생 내역 삭제
  DELETE FROM job_assignments WHERE "jobId" = p_job_id;

  -- 2. 직업 삭제
  DELETE FROM jobs WHERE id = p_job_id;
END;
$$;


