returns void as $$
begin
  -- 1-1. 자식 데이터 먼저 삭제
  delete from student_stocks where "userId" = p_user_id;
  delete from student_savings where "userId" = p_user_id;

  -- [핵심 수정] job_assignments의 컬럼명을 studentUserId로 변경하여 오류 해결
  delete from job_assignments where "studentUserId" = p_user_id;

  -- 1-2. 거래 내역 삭제 (보낸거, 받은거, 계좌주인인거)
  delete from transactions where "receiverId" = p_user_id or "senderId" = p_user_id;
  delete from transactions where "accountId" in (select "accountId" from accounts where "userId" = p_user_id);

  -- 1-3. 계좌 및 유저 삭제
  delete from accounts where "userId" = p_user_id;
  delete from users where "userId" = p_user_id;
end;
$$ language plpgsql;

-- 2. 직업 삭제 함수 (기존 유지)
create or replace function delete_job(p_job_id uuid)
returns void as $$
begin
  delete from job_assignments where "jobId" = p_job_id;
  delete from jobs where id = p_job_id;
end;
$$ language plpgsql;

