### 1단계: Supabase SQL 쿼리 실행

Supabase 대시보드의 **SQL Editor**에서 아래 코드를 복사하여 **RUN** 해주세요.
이 쿼리는 세금 테이블을 만들고, 월급 지급 시 소득세를 떼는 로직과, 세금을 납부하는 로직을 포함하고 있습니다.

```sql
-- 1. 세금 항목 테이블 생성 (고지서 정보)
CREATE TABLE IF NOT EXISTS public.tax_items (
    id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    name text NOT NULL,
    amount numeric NOT NULL,
    due_date timestamp with time zone NOT NULL,
    created_at timestamp with time zone DEFAULT now()
);

-- 2. 세금 납부 대상자 테이블 생성 (누가 냈는지 기록)
CREATE TABLE IF NOT EXISTS public.tax_recipients (
    id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    tax_id uuid REFERENCES public.tax_items(id) ON DELETE CASCADE,
    student_user_id text REFERENCES public.users("userId") ON DELETE CASCADE,
    is_paid boolean DEFAULT false,
    paid_at timestamp with time zone,
    created_at timestamp with time zone DEFAULT now()
);

-- 3. [소득세 로직] 주급 지급 함수 수정 (10% 자동 차감)
CREATE OR REPLACE FUNCTION pay_job_salary(p_job_id uuid)
RETURNS text
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  v_job RECORD;
  v_student RECORD;
  v_account_id text;
  v_salary numeric;
  v_tax numeric;
  v_net_salary numeric;
  v_count integer := 0;
BEGIN
  -- 직업 정보 조회
  SELECT * INTO v_job FROM jobs WHERE id = p_job_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'Job not found'; END IF;

  v_salary := v_job.salary + COALESCE(v_job.incentive, 0);
  v_tax := v_salary * 0.1; -- 소득세 10%
  v_net_salary := v_salary - v_tax; -- 실수령액

  FOR v_student IN 
    SELECT student_user_id FROM job_assignments WHERE job_id = p_job_id
  LOOP
    -- 학생 계좌 조회
    SELECT "accountId" INTO v_account_id FROM accounts WHERE "userId" = v_student.student_user_id;

    IF v_account_id IS NOT NULL THEN
      -- 1. 월급 입금 기록 (TransactionType: Salary)
      INSERT INTO transactions ("transactionId", "accountId", type, amount, date, description)
      VALUES (gen_random_uuid(), v_account_id, 'Salary', v_salary, now(), v_job.job_name || ' 주급');

      -- 2. 소득세 출금 기록 (TransactionType: Tax)
      INSERT INTO transactions ("transactionId", "accountId", type, amount, date, description)
      VALUES (gen_random_uuid(), v_account_id, 'Tax', -v_tax, now(), '소득세 (10%)');

      -- 3. 계좌 잔액 업데이트 (실수령액만큼 증가)
      UPDATE accounts SET balance = balance + v_net_salary WHERE "accountId" = v_account_id;

      v_count := v_count + 1;
    END IF;
  END LOOP;

  -- 보너스 초기화 및 지급일 업데이트
  UPDATE jobs SET incentive = 0, "lastPaidDate" = now() WHERE id = p_job_id;

  RETURN v_count || '명에게 주급 지급 완료 (소득세 10% 차감)';
END;
$$;

-- 4. [세금 생성] 선생님이 세금 고지서를 만드는 함수
CREATE OR REPLACE FUNCTION create_tax(
    p_name text, 
    p_amount numeric, 
    p_due_date timestamp with time zone, 
    p_student_ids text[]
)
RETURNS text
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
    v_tax_id uuid;
    v_student_id text;
BEGIN
    -- 세금 항목 생성
    INSERT INTO tax_items (name, amount, due_date)
    VALUES (p_name, p_amount, p_due_date)
    RETURNING id INTO v_tax_id;

    -- 대상 학생들에게 고지서 발송
    FOREACH v_student_id IN ARRAY p_student_ids
    LOOP
        INSERT INTO tax_recipients (tax_id, student_user_id)
        VALUES (v_tax_id, v_student_id);
    END LOOP;

    RETURN '세금 고지서가 생성되었습니다.';
END;
$$;

-- 5. [세금 납부] 학생이 세금을 내는 함수
CREATE OR REPLACE FUNCTION pay_tax(
    p_user_id text,
    p_tax_id uuid
)
RETURNS text
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
    v_tax RECORD;
    v_recipient RECORD;
    v_account RECORD;
    v_teacher_account_id text;
BEGIN
    -- 세금 정보 조회
    SELECT * INTO v_tax FROM tax_items WHERE id = p_tax_id;

    -- 납부 대상 확인
    SELECT * INTO v_recipient FROM tax_recipients 
    WHERE tax_id = p_tax_id AND student_user_id = p_user_id;

    IF NOT FOUND THEN RAISE EXCEPTION '납부 대상이 아닙니다.'; END IF;
    IF v_recipient.is_paid THEN RAISE EXCEPTION '이미 납부했습니다.'; END IF;

    -- 학생 계좌 조회
    SELECT * INTO v_account FROM accounts WHERE "userId" = p_user_id;
    IF v_account.balance < v_tax.amount THEN RAISE EXCEPTION '잔액이 부족합니다.'; END IF;

    -- 선생님(국고) 계좌 조회 (Role이 teacher인 사람 중 첫 번째 계좌)
    -- 만약 선생님 계좌가 없으면 돈은 증발(회수) 처리됩니다.
    SELECT a."accountId" INTO v_teacher_account_id 
    FROM accounts a
    JOIN users u ON a."userId" = u."userId"
    WHERE u.role = 'teacher'
    LIMIT 1;

    -- 1. 학생 계좌에서 차감 및 거래 내역 기록
    UPDATE accounts SET balance = balance - v_tax.amount WHERE "accountId" = v_account."accountId";

    INSERT INTO transactions ("transactionId", "accountId", type, amount, date, description)
    VALUES (gen_random_uuid(), v_account."accountId", 'Tax', -v_tax.amount, now(), v_tax.name || ' 납부');

    -- 2. 선생님 계좌로 입금 (국고 수입)
    IF v_teacher_account_id IS NOT NULL THEN
        UPDATE accounts SET balance = balance + v_tax.amount WHERE "accountId" = v_teacher_account_id;

        INSERT INTO transactions ("transactionId", "accountId", type, amount, date, description, "senderId")
        VALUES (gen_random_uuid(), v_teacher_account_id, 'Tax', v_tax.amount, now(), v_tax.name || ' 수납', p_user_id);
    END IF;

    -- 3. 납부 상태 업데이트
    UPDATE tax_recipients SET is_paid = true, paid_at = now() 
    WHERE id = v_recipient.id;

    RETURN '세금 납부가 완료되었습니다.';
END;
$$;

-- 6. 권한 부여
GRANT ALL ON public.tax_items TO anon, authenticated, service_role;
GRANT ALL ON public.tax_recipients TO anon, authenticated, service_role;
```

