-- 3. [문제 3, 5 해결] 주급 지급 함수 수정
-- (국고에서 출금 + job_name 컬럼명 오류 수정 + 소득세 처리)
CREATE OR REPLACE FUNCTION pay_job_salary(p_job_id uuid)
RETURNS text
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  v_job RECORD;
  v_student RECORD;
  v_student_account_id text;
  v_teacher_account_id text;
  v_salary numeric;
  v_tax numeric;
  v_count integer := 0;
BEGIN
  -- 1. 선생님(국고) 계좌 찾기
  SELECT a."accountId" INTO v_teacher_account_id 
  FROM accounts a JOIN users u ON a."userId" = u."userId" 
  WHERE u.role = 'teacher' LIMIT 1;

  IF v_teacher_account_id IS NULL THEN
    RAISE EXCEPTION '관리자(선생님) 계좌를 찾을 수 없어 주급을 지급할 수 없습니다.';
  END IF;

  -- 2. 직업 정보 조회 (컬럼명 "jobName"으로 정확히 참조하기 위해 변수에 할당)
  SELECT * INTO v_job FROM jobs WHERE id = p_job_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'Job not found'; END IF;

  v_salary := v_job.salary + COALESCE(v_job.incentive, 0);
  v_tax := v_salary * 0.1; -- 소득세 10%

  -- 3. 해당 직업을 가진 학생들에게 지급 루프
  FOR v_student IN 
    SELECT "studentUserId" FROM job_assignments WHERE "jobId" = p_job_id
  LOOP
    -- 학생 계좌 조회
    SELECT "accountId" INTO v_student_account_id FROM accounts WHERE "userId" = v_student."studentUserId";

    IF v_student_account_id IS NOT NULL THEN
      -- A. [주급 지급] 국고 -> 학생 (Transaction: Salary)
      -- 국고 출금
      UPDATE accounts SET balance = balance - v_salary WHERE "accountId" = v_teacher_account_id;
      -- 학생 입금
      UPDATE accounts SET balance = balance + v_salary WHERE "accountId" = v_student_account_id;

      -- 거래 내역 (학생 입장)
      INSERT INTO transactions ("transactionId", "accountId", type, amount, date, description, "senderId")
      VALUES (gen_random_uuid(), v_student_account_id, 'Salary', v_salary, now(), v_job."jobName" || ' 주급', 'teacher'); -- v_job."jobName"으로 수정

      -- B. [소득세 징수] 학생 -> 국고 (Transaction: Tax)
      -- 학생 출금
      UPDATE accounts SET balance = balance - v_tax WHERE "accountId" = v_student_account_id;
      -- 국고 입금
      UPDATE accounts SET balance = balance + v_tax WHERE "accountId" = v_teacher_account_id;

      -- 거래 내역 (학생 입장 - 소득세 차감)
      INSERT INTO transactions ("transactionId", "accountId", type, amount, date, description, "receiverId")
      VALUES (gen_random_uuid(), v_student_account_id, 'Tax', -v_tax, now(), '소득세 (10%)', 'teacher');

      v_count := v_count + 1;
    END IF;
  END LOOP;

  -- 보너스 초기화 및 지급일 업데이트
  UPDATE jobs SET incentive = 0, "lastPaidDate" = now() WHERE id = p_job_id;

  RETURN v_count || '명에게 주급 지급 완료 (국고 차감, 소득세 징수)';
END;
$$;


-- 4. [문제 4 해결] 은행원 거래 함수 수정 (국고 연동)
CREATE OR REPLACE FUNCTION banker_transaction(
    p_student_user_id text,
    p_amount numeric,
    p_type text -- 'Deposit' or 'Withdrawal'
)
RETURNS json
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
    v_student_account_id text;
    v_teacher_account_id text;
    v_student_name text;
    v_new_balance numeric;
BEGIN
    -- 1. 학생 계좌 및 이름 확인
    SELECT a."accountId", u.name INTO v_student_account_id, v_student_name
    FROM accounts a
    JOIN users u ON a."userId" = u."userId"
    WHERE a."userId" = p_student_user_id;

    IF v_student_account_id IS NULL THEN
