DROP FUNCTION IF EXISTS banker_transaction(text, numeric, text);
DROP FUNCTION IF EXISTS banker_transaction(text, numeric, public.transaction_type);

-- 2. 함수 재생성 (p_type을 text로 통일하여 모호함 제거)
-- 기능: 은행원이 입/출금 시 국고(선생님 지갑)와 연동됨
CREATE OR REPLACE FUNCTION banker_transaction(
    p_student_user_id text,
    p_amount numeric,
    p_type text -- 'Deposit' or 'Withdrawal' (문자열로 받음)
)
RETURNS json
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
    v_student_account_id text;
    v_teacher_account_id text;
    v_student_name text;
    v_new_balance numeric;
BEGIN
    -- 1. 학생 계좌 및 이름 확인
    SELECT a."accountId", u.name INTO v_student_account_id, v_student_name
    FROM accounts a
    JOIN users u ON a."userId" = u."userId"
    WHERE a."userId" = p_student_user_id;

    IF v_student_account_id IS NULL THEN
        RAISE EXCEPTION '학생 계좌를 찾을 수 없습니다.';
    END IF;

    -- 2. 선생님(국고) 계좌 확인
    SELECT a."accountId" INTO v_teacher_account_id 
    FROM accounts a JOIN users u ON a."userId" = u."userId" 
    WHERE u.role = 'teacher' LIMIT 1;

    IF v_teacher_account_id IS NULL THEN
        RAISE EXCEPTION '관리자(선생님) 계좌가 없어 은행 업무를 처리할 수 없습니다.';
    END IF;

    -- 3. 거래 처리
    IF p_type = 'Deposit' THEN
        -- [입금]: 국고 -> 학생
        -- 국고 잔액 감소
        UPDATE accounts SET balance = balance - p_amount WHERE "accountId" = v_teacher_account_id;
        -- 학생 잔액 증가
        UPDATE accounts SET balance = balance + p_amount WHERE "accountId" = v_student_account_id
        RETURNING balance INTO v_new_balance;

        -- 거래 기록 (학생)
        INSERT INTO transactions ("transactionId", "accountId", type, amount, date, description, "senderId")
        VALUES (gen_random_uuid(), v_student_account_id, 'Deposit', p_amount, now(), '은행 창구 입금', 'banker');

    ELSIF p_type = 'Withdrawal' THEN
        -- [출금]: 학생 -> 국고
        -- 잔액 확인
        IF (SELECT balance FROM accounts WHERE "accountId" = v_student_account_id) < p_amount THEN
            RAISE EXCEPTION '학생의 잔액이 부족합니다.';
        END IF;

        -- 학생 잔액 감소
        UPDATE accounts SET balance = balance - p_amount WHERE "accountId" = v_student_account_id
        RETURNING balance INTO v_new_balance;
        -- 국고 잔액 증가
        UPDATE accounts SET balance = balance + p_amount WHERE "accountId" = v_teacher_account_id;

        -- 거래 기록 (학생)
        INSERT INTO transactions ("transactionId", "accountId", type, amount, date, description, "receiverId")
        VALUES (gen_random_uuid(), v_student_account_id, 'Withdrawal', -p_amount, now(), '은행 창구 출금', 'banker');

    ELSE
        RAISE EXCEPTION '잘못된 거래 유형입니다.';
    END IF;

    RETURN json_build_object(
        'success', true,
        'message', v_student_name || ' 학생에게 ' || p_amount || '권 ' || 
                   CASE WHEN p_type = 'Deposit' THEN '입금' ELSE '출금' END || ' 완료'
    );
END;
$$;

-- 3. 권한 부여
GRANT EXECUTE ON FUNCTION banker_transaction(text, numeric, text) TO anon, authenticated, service_role;

네, 확인해 주셔서 감사합니다. 권쌤 지갑(국고)에서도 은행원 거래 내역이 이중으로 기록되도록 데이터베이스 함수를 수정하겠습니다.

이 작업을 위해 **Supabase SQL Editor**에서 아래 코드를 복사하여 **실행(RUN)**해 주세요. 프론트엔드 코드는 수정할 필요 없이, 이 SQL 실행만으로 기능이 적용됩니다.

### Supabase SQL 쿼리 (복사 후 실행)

```sql
-- 은행원 거래 함수 수정 (국고 거래 내역 추가 기록)
CREATE OR REPLACE FUNCTION banker_transaction(
    p_student_user_id text,
    p_amount numeric,
    p_type text -- 'Deposit' or 'Withdrawal'
)
RETURNS json
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
    v_student_account_id text;
    v_teacher_account_id text;
    v_student_name text;
    v_new_balance numeric;
BEGIN
    -- 1. 학생 계좌 및 이름 확인
    SELECT a."accountId", u.name INTO v_student_account_id, v_student_name
    FROM accounts a
    JOIN users u ON a."userId" = u."userId"
    WHERE a."userId" = p_student_user_id;

    IF v_student_account_id IS NULL THEN
        RAISE EXCEPTION '학생 계좌를 찾을 수 없습니다.';
    END IF;

    -- 2. 선생님(국고) 계좌 확인
    SELECT a."accountId" INTO v_teacher_account_id 
    FROM accounts a JOIN users u ON a."userId" = u."userId" 
    WHERE u.role = 'teacher' LIMIT 1;

    IF v_teacher_account_id IS NULL THEN
        RAISE EXCEPTION '관리자(선생님) 계좌가 없어 은행 업무를 처리할 수 없습니다.';
    END IF;

    -- 3. 거래 처리
    IF p_type = 'Deposit' THEN
        -- [입금]: 국고 -> 학생
        -- 잔액 변경
        UPDATE accounts SET balance = balance - p_amount WHERE "accountId" = v_teacher_account_id;
        UPDATE accounts SET balance = balance + p_amount WHERE "accountId" = v_student_account_id
        RETURNING balance INTO v_new_balance;

        -- [기록 1] 학생 거래 내역 (기존 동일)
        INSERT INTO transactions ("transactionId", "accountId", type, amount, date, description, "senderId")
        VALUES (gen_random_uuid(), v_student_account_id, 'Deposit', p_amount, now(), '은행 창구 입금', 'banker');

