        INSERT INTO transactions ("transactionId", "accountId", type, amount, date, description, "receiverId")
        VALUES (gen_random_uuid(), v_teacher_account_id, 'Withdrawal', -p_amount, now(), '은행 창구 입금 (' || v_student_name || ')', v_student_account_id);

    ELSIF p_type = 'Withdrawal' THEN
        -- [출금]: 학생 -> 국고
        -- 잔액 확인
        IF (SELECT balance FROM accounts WHERE "accountId" = v_student_account_id) < p_amount THEN
            RAISE EXCEPTION '학생의 잔액이 부족합니다.';
        END IF;

        -- 잔액 변경
        UPDATE accounts SET balance = balance - p_amount WHERE "accountId" = v_student_account_id
        RETURNING balance INTO v_new_balance;
        UPDATE accounts SET balance = balance + p_amount WHERE "accountId" = v_teacher_account_id;

        -- [기록 1] 학생 거래 내역 (기존 동일)
        INSERT INTO transactions ("transactionId", "accountId", type, amount, date, description, "receiverId")
        VALUES (gen_random_uuid(), v_student_account_id, 'Withdrawal', -p_amount, now(), '은행 창구 출금', 'banker');

        -- [기록 2] 선생님 거래 내역 (신규 추가!)
        -- 국고 입장에서는 돈이 들어오는 것이므로 Deposit으로 기록합니다.
        INSERT INTO transactions ("transactionId", "accountId", type, amount, date, description, "senderId")
        VALUES (gen_random_uuid(), v_teacher_account_id, 'Deposit', p_amount, now(), '은행 창구 출금 (' || v_student_name || ')', v_student_account_id);

    ELSE
        RAISE EXCEPTION '잘못된 거래 유형입니다.';
    END IF;

    RETURN json_build_object(
